import { TOP_ALIGN, BOTTOM_ALIGN } from '../../../core/align-constants';
import { ORDINAL_DATATYPE } from '../../../core/datatype-constants';
import { BrushComponentTooltip } from '../../../legend/colorband/colorband-brush-tooltip';
import { d3_ascending } from '../../../core/d3-constants';
import { d3_values } from '../../../utils/zcutils';
import { getSvgTransform } from '../../../utils/svg-transforms';
// import { legend_helpers } from '../../../legend/legend-helper';
import { legend_helpers } from '../../../core/main-zc-init';
import { getBrushTooltipContent, getActiveDiscreteDomain } from '../../../legend/colorband/colorband-brush-tooltip-content';
import { getDisabledOptions } from '../../../legend/events/legend-event-helpers';

export function brushTooltip(behaviourEventInstance) {
    let brushInstance = behaviourEventInstance.instance,
        component = brushInstance.options.component,
        { globalFont, encode } = component.spec,
        { brushOptions } = component,
        { config, reversed, customActions, handles: handleOptions } = brushOptions,
        disabledOptions = getDisabledOptions(config),
        tooltipOptions = encode === 'clr' ? disabledOptions.slider.tooltip : disabledOptions.tooltip, // TODO: work here to get tooltip options
        dataFinder = behaviourEventInstance.dataFinder.brush,
        text = d => {
            let point = dataFinder(behaviourEventInstance, null, brushInstance.getSelection()),
                data = getTooltipData(brushOptions, point, reversed);
            return getBrushTooltipContent(data, d, brushOptions);
        },
        orient = legend_helpers.getOrient(config),
        options =
            encode === 'clr'
                ? {}
                : {
                      translate: ele => getSvgTransform(ele).translate,
                      boxElement: ele => ele.selectAll('path'),
                      isHorizontal: handleOptions ? undefined : orient => orient === TOP_ALIGN || orient === BOTTOM_ALIGN
                  };

    return new BrushComponentTooltip(tooltipOptions, brushInstance, orient, text, null, customActions, globalFont, options);
}

function getTooltipData(options, point, strictReverse) {
    let { ranges, reversed, config, sizeScale: scale, datatype: dataType, singleDomainContinuous } = options;
    point = point || config.filter.range;
    var data;

    if (singleDomainContinuous) {
        return scale.domain();
    }

    if (point) {
        if (dataType === ORDINAL_DATATYPE) {
            let extentData = [point[0], point[point.length - 1]];
            data = reversed ? d3_values(extentData).reverse() : extentData;
        } else if (ranges && ranges.length) {
            data = getActiveDiscreteDomain(d3_values(point).sort(d3_ascending), ranges);
        } else {
            data = strictReverse ? d3_values(point).reverse() : point;
        }

        return data;
    }
}
